angular.module('starter').controller('PaymentModalController',function($scope,Dialog,PaymentMethod){angular.extend($scope,{isLoading:!0,paymentGateways:[]});$scope.closeModal=function(){PaymentMethod.closeModal()};$scope.methodIsAllowed=function(paymentMethod){return $scope.options.methods.indexOf(paymentMethod)>=0};$scope.fetchGateways=function(){PaymentMethod.fetchGateways().then(function(payload){$scope.paymentGateways=payload.gateways},function(error){Dialog.alert('Error',error.message,'OK',-1,'payment_method')}).then(function(){$scope.isLoading=!1})};$scope.paymentModal={onSelect:function(paymentMethod){$scope.options.onSelect(paymentMethod)}};$scope.fetchGateways()});angular.module('starter').service('PaymentMethod',function(Modal,$pwaRequest){var service={modal:null,PAYMENT:'payment',AUTHORIZATION:'authorization',SETUP:'setup',ACTION_PAY:'pay',ACTION_AUTHORIZE:'authorize',ACTION_DELETE:'delete',onStart:function(){},openModal:function($scope,options){Modal.fromTemplateUrl('./features/payment_method/assets/templates/l1/payment-modal.html',{scope:angular.extend($scope,{options:options}),animation:'slide-in-right-left'}).then(function(modal){service.modal=modal;service.modal.show()})},closeModal:function(){service.modal.remove()},fetchGateways:function(){return $pwaRequest.get('/paymentmethod/mobile_gateway/fetch-all')}};return service});Features.insertCSS("","payment_method")